import{_ as t,o as a,c as o,a2 as r}from"./chunks/framework.CKCxdkvf.js";const u=JSON.parse('{"title":"PRD-007 — Multi-Language Support","description":"","frontmatter":{},"headers":[],"relativePath":"prd/PRD-007.md","filePath":"prd/PRD-007.md"}'),n={name:"prd/PRD-007.md"};function i(s,e,d,l,c,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="prd-007-—-multi-language-support" tabindex="-1">PRD-007 — Multi-Language Support <a class="header-anchor" href="#prd-007-—-multi-language-support" aria-label="Permalink to &quot;PRD-007 — Multi-Language Support&quot;">​</a></h1><p><em>Orrery · Product Requirements · v0.1 · May 2026</em></p><blockquote><p><strong>Status:</strong> Draft <strong>Depends on:</strong> RFC-010 (open — must close before implementation begins) <strong>Slice:</strong> v2.0 <strong>Screens affected:</strong> All (cross-cutting) <strong>Principles:</strong> physics first, attribution is design (PA §principles) Why this is a PRD · Translation is the single highest-leverage action to expand reach: ~3B speakers are excluded by English-only state. The architecture is already in place (ADR-017); this PRD defines what &quot;shipped in language X&quot; means in terms of UX, terminology accuracy, and acceptance gates so a translation pass for any locale has a clear bar to clear.</p></blockquote><hr><h2 id="§why" tabindex="-1">§why <a class="header-anchor" href="#§why" aria-label="Permalink to &quot;§why&quot;">​</a></h2><p>Space exploration is a global endeavour. The simulator&#39;s current English-only state excludes the majority of the world&#39;s space agencies&#39; home audiences — including the 1.1B Mandarin speakers watching CNSA&#39;s Tianwen missions, the 600M Hindi speakers following ISRO&#39;s Chandrayaan and Gaganyaan programmes, and the hundreds of millions of Spanish and French speakers engaged with ESA and Latin America&#39;s growing space sector.</p><p>The i18n architecture is already in place. This PRD defines what the user-facing translation experience looks like, and what &quot;done&quot; means for each language added.</p><hr><h2 id="§audiences" tabindex="-1">§audiences <a class="header-anchor" href="#§audiences" aria-label="Permalink to &quot;§audiences&quot;">​</a></h2><p>This feature serves all three existing audiences, with additional reach into new populations:</p><p><strong>The curious learner</strong> — now reached in their native language. A student in Mumbai, a teacher in São Paulo, a teenager in Tokyo — all currently excluded. Translation is the single highest-leverage action to expand this audience.</p><p><strong>The STEM student</strong> — particularly served by accurate physics terminology in their language. A Japanese student who already knows what a <em>ホーマン遷移軌道</em> (Hohmann transfer) is should see that term, not a transliteration.</p><p><strong>The space enthusiast</strong> — the community of people who follow JAXA, CNSA, ISRO, DLR, and Roscosmos missions. These people are deeply knowledgeable; translation quality matters. Errors in orbital mechanics terminology will be noticed and will damage credibility.</p><hr><h2 id="§promises" tabindex="-1">§promises <a class="header-anchor" href="#§promises" aria-label="Permalink to &quot;§promises&quot;">​</a></h2><p>The simulator makes these promises to a user in a non-English locale:</p><ol><li><strong>The full experience is available in their language.</strong> No screen, panel, or label falls back to English mid-session.</li><li><strong>Physics terminology is accurate.</strong> Terms like &quot;Hohmann transfer&quot;, &quot;delta-v&quot;, &quot;Tsiolkovsky equation&quot;, and &quot;porkchop plot&quot; are rendered using the accepted convention in that language&#39;s scientific community — not machine-translated literally.</li><li><strong>The locale is shareable.</strong> Switching language updates the URL <code>?lang=</code> parameter so the choice is bookmarkable and copy-pasteable. (Cross-session persistence via storage is intentionally not promised — see CLAUDE.md &quot;do not use localStorage&quot; rule.)</li><li><strong>Switching language is effortless.</strong> A language picker is accessible from every screen in one interaction.</li><li><strong>No content is hidden.</strong> All 32 missions in the library, all configurator parameters, all HUD labels, all fact panels — translated.</li></ol><hr><h2 id="§language-picker-ux" tabindex="-1">§language-picker UX <a class="header-anchor" href="#§language-picker-ux" aria-label="Permalink to &quot;§language-picker UX&quot;">​</a></h2><p>A language selector is added to the navigation bar (right side, before the existing controls).</p><p><strong>Behaviour:</strong></p><ul><li>Displays the current locale as a short label (e.g. <code>EN</code>, <code>ES</code>, <code>日本語</code>, <code>中文</code>, <code>عربي</code>)</li><li>On click/tap: opens a dropdown listing all available locales by their native name (not English name) <ul><li>e.g. <code>Español</code>, <code>Français</code>, <code>Deutsch</code>, <code>日本語</code>, <code>中文（简体）</code>, <code>हिन्दी</code>, <code>Português</code>, <code>العربية</code>, <code>한국어</code>, <code>Русский</code>, <code>Italiano</code></li></ul></li><li>Selection takes effect immediately — the URL is updated to <code>?lang=&lt;code&gt;</code> so the navigation re-renders without a full reload</li><li>The URL <code>?lang=</code> parameter is the single source of truth; no <code>localStorage</code> / <code>sessionStorage</code> (per CLAUDE.md)</li><li>On first visit (no <code>?lang=</code> in URL): browser locale is detected via <code>navigator.language</code>; if a supported locale matches, the URL is rewritten via <code>replaceState</code> to <code>?lang=&lt;code&gt;</code>; otherwise falls back to English</li></ul><p><strong>RTL handling:</strong></p><ul><li>When Arabic is active, <code>&lt;html dir=&quot;rtl&quot;&gt;</code> is set</li><li>All UI chrome mirrors correctly (nav, panels, bottom bar)</li><li>Three.js canvas and 2D plots are direction-neutral and unaffected</li></ul><hr><h2 id="§string-scope" tabindex="-1">§string scope <a class="header-anchor" href="#§string-scope" aria-label="Permalink to &quot;§string scope&quot;">​</a></h2><p>All translatable strings are in the existing locale files. For reference, the categories are:</p><table tabindex="0"><thead><tr><th>Category</th><th>Examples</th><th>Approx. string count</th></tr></thead><tbody><tr><td>Navigation labels</td><td>Explorer, Configurator, Mission Arc, Library, Earth, Moon</td><td>~20</td></tr><tr><td>Configurator controls</td><td>Launch window, Payload mass, Engine type, Departure date</td><td>~60</td></tr><tr><td>HUD labels</td><td>Velocity, Distance from Earth, Signal delay, Mission elapsed</td><td>~40</td></tr><tr><td>Mission metadata</td><td>Mission names, agency names, destination labels, status</td><td>~120</td></tr><tr><td>Fact / editorial text</td><td>Body descriptions, mission summaries, capability callouts</td><td>~800</td></tr><tr><td>Error / status messages</td><td>Loading, no result, out of range, worker failed</td><td>~30</td></tr><tr><td>Accessibility labels</td><td>ARIA labels on all interactive controls</td><td>~80</td></tr><tr><td><strong>Total</strong></td><td></td><td><strong>~1,150 strings</strong></td></tr></tbody></table><p>Physics terms (delta-v, Isp, Hohmann, porkchop plot, etc.) must use the accepted scientific convention in each target language, not a literal translation. See §translation-guidance below.</p><hr><h2 id="§translation-guidance" tabindex="-1">§translation-guidance <a class="header-anchor" href="#§translation-guidance" aria-label="Permalink to &quot;§translation-guidance&quot;">​</a></h2><p>Translators must be briefed on the following before beginning work:</p><p><strong>Terms to use by scientific convention (do not translate literally):</strong></p><table tabindex="0"><thead><tr><th>English term</th><th>Notes</th></tr></thead><tbody><tr><td>Delta-v (Δv)</td><td>Use the symbol universally; add native-language gloss in first use only</td></tr><tr><td>Hohmann transfer</td><td>Proper noun — do not translate; transliterate only if no established usage</td></tr><tr><td>Isp (specific impulse)</td><td>Use abbreviation; add native gloss</td></tr><tr><td>Porkchop plot</td><td>Established term in mission planning; may be translated or transliterated per convention</td></tr><tr><td>Tsiolkovsky equation</td><td>Proper noun — transliterate per convention</td></tr><tr><td>Aphelion / Perihelion</td><td>Established astronomical terms with accepted equivalents in most languages</td></tr><tr><td>C3 (characteristic energy)</td><td>Use symbol universally</td></tr><tr><td>SOI (sphere of influence)</td><td>Translate the concept; use established equivalent</td></tr><tr><td>Astronomical Unit (AU)</td><td>Use <code>UA</code> in Spanish/French/Portuguese; <code>AU</code> elsewhere</td></tr></tbody></table><p><strong>Mission and agency names:</strong> Use the official romanisation / official native-language name as published by the agency itself.</p><ul><li>e.g. CNSA publishes <em>天问</em> (Tianwen) in Chinese and <em>Tianwen</em> in English — use both</li><li>e.g. JAXA uses <em>はやぶさ</em> (Hayabusa) — use the official romanisation for non-Japanese locales</li></ul><p><strong>Number formatting:</strong> Respect locale conventions.</p><ul><li><code>1,000,000</code> km (EN) → <code>1.000.000</code> km (DE) → <code>1 000 000</code> km (FR)</li><li>The i18n layer handles this via <code>Intl.NumberFormat</code> — translators do not need to format numbers in strings</li></ul><hr><h2 id="§language-rollout" tabindex="-1">§language rollout <a class="header-anchor" href="#§language-rollout" aria-label="Permalink to &quot;§language rollout&quot;">​</a></h2><p>Phasing is subject to RFC-010 resolution. Proposed waves:</p><p><strong>Wave 1 — v2.0 (Latin script; lower implementation risk)</strong></p><table tabindex="0"><thead><tr><th>Language</th><th>Locale code</th><th>Primary space agency served</th></tr></thead><tbody><tr><td>Spanish</td><td><code>es</code></td><td>ESA contributors; Latin America</td></tr><tr><td>French</td><td><code>fr</code></td><td>CNES, ESA</td></tr><tr><td>German</td><td><code>de</code></td><td>DLR, ESA</td></tr><tr><td>Portuguese (BR)</td><td><code>pt-BR</code></td><td>AEB (Brazil)</td></tr><tr><td>Italian</td><td><code>it</code></td><td>ASI, ESA</td></tr></tbody></table><p><strong>Wave 2 — v2.1 (CJK scripts; requires font strategy from RFC-010 OQ-2)</strong></p><table tabindex="0"><thead><tr><th>Language</th><th>Locale code</th><th>Primary space agency served</th></tr></thead><tbody><tr><td>Mandarin (Simplified)</td><td><code>zh-CN</code></td><td>CNSA, CMSA</td></tr><tr><td>Japanese</td><td><code>ja</code></td><td>JAXA</td></tr><tr><td>Korean</td><td><code>ko</code></td><td>KARI</td></tr></tbody></table><p><strong>Wave 3 — v2.2 (non-Latin, non-CJK; requires RTL audit for Arabic)</strong></p><table tabindex="0"><thead><tr><th>Language</th><th>Locale code</th><th>Primary space agency served</th></tr></thead><tbody><tr><td>Hindi</td><td><code>hi</code></td><td>ISRO</td></tr><tr><td>Russian</td><td><code>ru</code></td><td>Roscosmos</td></tr><tr><td>Arabic</td><td><code>ar</code></td><td>UAESA</td></tr></tbody></table><hr><h2 id="§definition-of-done-per-language" tabindex="-1">§definition-of-done (per language) <a class="header-anchor" href="#§definition-of-done-per-language" aria-label="Permalink to &quot;§definition-of-done (per language)&quot;">​</a></h2><p>A language is considered <strong>done</strong> when all of the following are true:</p><ul><li>[ ] All ~1,150 strings translated and reviewed by a native speaker with science/technical background</li><li>[ ] Physics terminology verified against the accepted convention for that language</li><li>[ ] All 6 screens render correctly with no truncation, overflow, or layout breaks at the translated string lengths</li><li>[ ] Language picker shows the language in its native name</li><li>[ ] Locale is shareable via URL <code>?lang=</code> (no storage; first-visit <code>navigator.language</code> detection rewrites the URL)</li><li>[ ] <code>prefers-reduced-motion</code> behaviour unchanged in the new locale</li><li>[ ] All ARIA labels translated (screen reader accessibility maintained)</li><li>[ ] For CJK: appropriate font loads correctly; no tofu (□) characters</li><li>[ ] For RTL (Arabic): all UI panels mirror correctly; no content clipping</li><li>[ ] Playwright e2e passes: language switch → all screens → no console errors</li></ul><hr><h2 id="§what-is-deferred" tabindex="-1">§what-is-deferred <a class="header-anchor" href="#§what-is-deferred" aria-label="Permalink to &quot;§what-is-deferred&quot;">​</a></h2><ul><li>Locale-specific unit preferences (km vs miles) — separate ADR</li><li>Regional mission data variation (e.g. showing CNSA-published mission data in Chinese locale) — future consideration</li><li>Dubbing or narration (audio is out of scope)</li><li>Locale-specific imagery or cultural adaptation (translation only; no asset changes)</li><li>Right-to-left canvas layouts (canvas is direction-neutral; not applicable)</li></ul><hr><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><table tabindex="0"><thead><tr><th>What</th><th>Where</th></tr></thead><tbody><tr><td>i18n architecture</td><td><code>docs/adr/ADR-017.md</code></td></tr><tr><td>Translation strategy RFC</td><td><code>docs/rfc/RFC-010.md</code></td></tr><tr><td>Accessibility spec</td><td><code>docs/rfc/RFC-005.md</code></td></tr><tr><td>Product authority</td><td><code>docs/prd/PA.md</code></td></tr><tr><td>v1.0 deferred list</td><td><code>docs/prd/PRD-006.md §deferred</code></td></tr><tr><td>ROADMAP</td><td><code>ROADMAP.md</code></td></tr></tbody></table>',57)])])}const p=t(n,[["render",i]]);export{u as __pageData,p as default};
